#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
const int N = 1010;

int n;
ll c, ans;
ll w[N], s[N];

void dfs(int p, ll cur) {
    if (cur > c) return;
    if (p == 0) {
        ans = max(ans, cur);
        return;
    }

    if (cur + s[p] <= ans) return;
    if (cur + s[p] <= c) {
        ans = max(ans, cur + s[p]);
        return;
    }

    if (cur + w[p] <= c)
        dfs(p - 1, cur + w[p]);

    dfs(p - 1, cur);
}

int main() {
    cin >> n >> c;
    for (int i = 1; i <= n; i++)
        cin >> w[i];
    for (int i = 1; i <= n; i++)
        s[i] = s[i - 1] + w[i];
    ans = 0;
    dfs(n, 0);
    cout << ans << endl;
    return 0;
}
